-- ============================================================
-- Legacy (Notion) Onboarding -> Supabase migration + backfill
-- Run in the Supabase SQL editor for project uzltbbrjidmjwwfakwve. Idempotent.
--
-- Historical onboarding forms migrated out of Notion (the old intake, pre-SyncView
-- form). Stored AS-IS: each record keeps its original question->answer list in the
-- `fields` jsonb, with NO remap to the new form schema. Powers the Templates ->
-- Onboarding -> "Old forms" section.
--
-- SECURITY: mirrors client_onboarding. Holds personal data (names, emails, phones),
-- so *** NO anon policy ***. Account LOGINS/PASSWORDS were stripped at export time and
-- are NOT present here. Reads: service-role only (the n8n legacy-onboarding-list webhook).
-- ============================================================

create table if not exists public.legacy_onboarding (
  id            text primary key,   -- original Notion page id
  slug          text,               -- wlNormalizeClient(first+last), matches analytics client key
  first_name    text,
  last_name     text,
  email         text,
  phone         text,
  submitted_on  text,               -- original submission time, verbatim
  fields        jsonb,              -- [{label,value},...] original Q&A, credential-free
  credentials   jsonb,              -- [{label,value},...] account logins; service-role only.
                                     -- Loaded OUT OF BAND (never committed to this repo);
                                     -- only the Kasper-gated onboarding-full edge fn returns it.
  source        text default 'notion-legacy',
  created_at    text                -- ISO parsed from submitted_on (for ordering)
);

-- For tables created before the credentials column existed:
alter table public.legacy_onboarding add column if not exists credentials jsonb;

alter table public.legacy_onboarding enable row level security;
revoke all on public.legacy_onboarding from anon;
revoke all on public.legacy_onboarding from authenticated;

-- ---- Backfill (21 clients) ----
insert into public.legacy_onboarding (id, slug, first_name, last_name, email, phone, submitted_on, fields, source, created_at)
values ('295bcb82c4bf81509103d26aca77eb9e', 'adrianarizzolo', 'Adriana', 'Rizzolo', 'support@bodytemple.church', '9084206221', 'October 23, 2025 5:22', '[{"label":"Who will need to be included in communication about the work we’re doing?","value":"Bee my VA support@bodytemple.church"},{"label":"Accounting Contact","value":"Same"},{"label":"Who is your IDEAL target customer?","value":"Wealthy and intelligent individuals and couples, who wish to restore intimacy as a living, breathing practice — not a performance or a fix.\n\nThe Initiated Woman — The Artist, Leader, Healer on the Edge of Becoming\n\nShe’s not new to this work.\nShe’s deep, creative, and spiritually fluent — already a space holder, coach, performer, or entrepreneur who’s been walking the path for years.. Queer- bisexual, a believer and lover of all things Divine and intense spiritual practice (but not religious.)\nShe’s built something real — a business, a following, a reputation — but beneath it all, her soul is whispering: there’s more.\n\nShe doesn’t just want success anymore.\nShe wants saturation — to soak back into her skin, into pleasure, into the sacred pulse beneath all the doing.\nShe’s ready to surrender another layer of the false self, to reclaim the sensual, chaotic, holy parts she left behind while trying to “make it.”\n\nShe comes to you not for tips or tactics —\nbut for initiation.\nFor transmission.\nFor the embodied permission to live her truth louder, softer, messier, freer.\n\n What She’s Really Longing For\n\nA somatic and spiritual initiation that invites her to embody the next evolution of her power.\n\nA return to her pleasure, eros, and soul truth as the source of her creative leadership.\n\nA community of peers who speak her language — women of depth, art, and devotion.\n\nTo shed the armor of the achiever and awaken the artist, the priestess, the lover again.\n\nWhy She’s Drawn to You\n\nBecause you’ve walked through the same fire.\nYou’ve known both the sacred grind and the sacred surrender.\nYou speak the language of the mystic and the entrepreneur, the healer and the hedonist.\nYou’ve turned grief into art, trauma into prayer, and desire into truth — and she knows she can trust you because you don’t just teach it.\nYou live it.\n\nYou’re the one who can guide her through the threshold —\nfrom the woman who’s mastered survival and success\nto the woman who’s devoted to soul, eros, and the ecstatic intelligence of her own body."},{"label":"Do you have any brand identity or guidelines that you have available for reference? If so, please share the link below:","value":"n/a redoing website"},{"label":"What are the PAIN points of the customers you help?","value":"1. The Burnout of the High-Functioning Mystic\n\nShe’s built her dream — but it’s starting to feel dry.\nShe can hold the world, but she’s starving to be held.\nThe very work that once lit her up now feels performative, overpolished, disconnected from soul.\n\n2. The Split Between Power and Pleasure\n\nShe’s learned how to lead, to earn, to command — but her body is craving surrender.\nMoney and success don’t feel like nourishment anymore.\nShe wants to soften without losing her fire — to lead from eros instead of adrenaline.\n\n3. Creative + Sexual Stagnation\n\nHer art or business feels stuck in repetition — she knows she’s here to express something bolder, riskier, truer.\nThere’s a new creative edge rising through her — raw, sensual, spiritual — and she needs a container that can hold that awakening without shaming or diluting it.\n\n4. The Ache for Devotional Depth\n\nTraditional spiritual spaces feel too sterile.\nFeminine empowerment spaces feel too shiny.\nShe’s seeking the holy middle ground — where body, God, and grief can coexist.\nShe wants ritual, not routine. Mystery, not marketing.\n\n\n\n1. Disconnection from the Body\n\nFeels numb, anxious, or dissociated — even while doing “healing work.”\nTired of living from the neck up, overanalyzing every feeling.\nLonging to feel alive again — through sensuality, voice, dance, and ritual.\n\n2. Fear of Being “Too Much” or “Not Enough”\n\nCarries shame around desire, anger, or grief.\nHas internalized spiritual and cultural conditioning to stay small, quiet, and composed.\nFears being judged or misunderstood if she reveals her raw truth or erotic nature.\n\n3. Burnout from Holding Others\n\nOver-giving healer / coach / artist who’s spiritually drained.\nFeels responsible for others’ emotions.\nLongs to be witnessed, not to hold.\n\n4. Longing for True Belonging\n\nFeels like she doesn’t fit in conventional spaces (wellness, religion, or even activism).\nCraves community where her wildness and grief are welcome.\nWants ritual, beauty, and connection that’s not performative — but real.\n\n5. Identity in Transition\n\nGoing through heartbreak, loss, creative rebirth, or spiritual awakening.\nFeeling the death of the old self but not yet sure how to embody the new.\nSearching for grounded guidance that honors both her body and her soul."},{"label":"What are the DESIRED OUTCOMES of the customers you help?","value":"Embodied Liberation\nThey want to feel safe in their body again — to move from numbness or anxiety into grounded sensual presence. They long to trust their own sensations as truth and return to their body as the temple of their devotion and power. Creative Freedom\nThey crave to unleash their voice, movement, and art without fear of being “too much.” They want to create from the wild pulse of their soul — to bring that energy into their work, relationships, and leadership.\n Emotional and Nervous System Regulation\nThey desire somatic mastery — the ability to move through grief, rage, and pleasure with skill and compassion. They want to stop being hijacked by overwhelm or self-doubt and start responding from clarity and inner power.\n Erotic Wholeness\nThey want to heal the split between spirituality and sexuality — to reclaim pleasure, boundaries, and intimacy as sacred portals to union with the divine.\n Ancestral and Collective Healing\nThey want to make peace with their lineage — to transmute inherited trauma and repair their relationship to the feminine, the body, and the earth.\n Authentic Relating and Leadership\nThey desire to show up in relationships and facilitation with integrity and heart — to be witnessed in truth, to hold others with skill, and to lead with depth and devotion.\n Integration of Power and Tenderness\nUltimately, they want to embody the paradox — fierce and soft, ecstatic and grounded, erotic and holy.\nThey come to Body Temple to remember how to live as art, prayer, and protest."},{"label":"What is your PROCESS for helping clients get from where they are to where they want to go?","value":"The Body Temple Process\nA nervous system–based path of embodied liberation and creative power\n1. Descent: Reconnecting to Sensation and Safety\nWe begin by slowing down enough to actually feel. Most of us have lived for years in fight, flight, or freeze — managing, performing, or dissociating.\nThrough gentle somatic tracking, breath, and grounding practices, we build capacity in the nervous system to tolerate what’s been avoided — grief, anger, fear, pleasure.\nWe learn how to pendulate between activation and rest, so the body starts to trust safety again.\nThis is where women begin to inhabit their bodies instead of managing them.\n2. Purification: Regulating Through Expression and Repair\nOnce there’s enough stability, we begin to move the stuck energy — the tension, the shutdown, the survival patterns.\nThrough trembling, sounding, and movement, the body discharges incomplete survival responses and reorganizes.\nWe explore shame, boundaries, and anger as intelligent signals — information from the body rather than something to suppress.\nThis phase is about re-patterning how we relate to our own energy — shifting from repression to regulation.\nIt’s how the body learns: I can feel and stay connected.\n3. Reclamation: Awakened Eros and Creative Flow\nAs the body’s baseline state becomes more regulated, more energy becomes available for pleasure, play, and creation.\nWe explore the social nervous system — how safety, love, and joy emerge when we’re co-regulated and expressed.\nThrough dance, voice, and ritual, women awaken eros as their natural life force — not performative sexuality, but the deep pulse of vitality that fuels artistry, intimacy, and devotion.\nThis is where trauma becomes creative power.\n4. Integration: Embodying Right Relationship\nFinally, we bring it all together — learning to anchor this embodied safety and truth in daily life.\nWe practice relational repair, boundaries, and authentic communication, so that nervous system regulation becomes collective, not just personal.\nThrough community witnessing, ritual, and reflection, we learn to stay connected while staying true.\nThis is how embodied liberation becomes leadership — how we bring the medicine of our own nervous systems into the world.\nBody Temple teaches women to move from protection to connection, from numbness to aliveness, and from self-management to soul-led regulation.\nThe Somatic Path of Sexual Reclamation\nA trauma-informed, nervous system–based approach to awakening eros and embodied intimacy\n1. Safety Before Sensuality: Rebuilding Trust in the Body\nTrue sexual healing doesn’t start with pleasure — it starts with safety.\nMost of us have internalized cultural, religious, and personal conditioning that keeps our sexual energy frozen or fragmented.\nBefore opening to touch, turn-on, or fantasy, we begin by orienting to safety through grounding, containment, and self-attunement practices.\nWe learn the difference between activation and arousal — between being turned on and being overwhelmed.\nAs the body learns that sensation isn’t dangerous, pleasure can emerge naturally — without force or performance.\n2. Sensation & Boundaries: Reclaiming the Skin as a Sacred Boundary\nThe skin is our first boundary — the meeting place between self and world.\nThrough somatic mapping, breath, and subtle self-touch, we explore how trauma and conditioning have shaped our sense of space and contact.\nThis work helps repair boundary ruptures stored in the nervous system, the ones that came from being touched without consent, seen too soon, or ignored when we needed presence.\nWe learn to say yes, no, maybe — from the body, not from social expectation.\nThis phase teaches that boundaries are not walls, but rhythms — how the body naturally opens and closes as it learns trust.\n3. Erotic Aliveness: Reclaiming Pleasure as Regulation\nOnce the system can hold sensation, we begin to cultivate erotic charge as life force.\nThrough movement, sounding, and guided touch, we learn how pleasure is not indulgence — it’s regulation.\nEros is the nervous system’s natural expression of connection and curiosity when it feels safe.\nWe explore the body’s “window of turn-on,” how the vagus nerve and pelvic diaphragm connect heart and genitals, and how breath widens the capacity to stay present in pleasure.\nThis is the territory where shame dissolves and we meet our true creative current — pleasure as prayer.\n4. Relational Eros: Embodying Love Without Losing Self\nAs we grow in our sexual self-awareness, we bring this aliveness into connection.\nWe practice co-regulation in intimacy — learning to stay embodied while being seen, desired, or rejected.\nThis includes nervous system education around attachment, trauma responses in relationship, and how to bring repair and truth into sexual dynamics.\nWe move from performing for love to relating from truth.\nThis is the sacred shift from sex as transaction to sex as transmission — a devotional act of mutual awakening.\n5. Integration: Eros as a Way of L"},{"label":"Please provide links to some examples of social media clips that you like from a design perspective:","value":"https://www.instagram.com/stella.porta/\nhttps://www.instagram.com/madelynmoon/\nhttps://www.instagram.com/sahdsimone/\nhttps://www.instagram.com/holistic.life.navigation/\nhttps://www.instagram.com/eroticsofliberation/"},{"label":"Please provide links to video thumbnails/cover images that you like from a design perspective:","value":"https://www.instagram.com/reel/DLfjn58NEdj/?utm_source=ig_web_copy_link&igsh=MzRlODBiNWFlZA==\n\nhttps://www.instagram.com/reel/DPOrGZCACM-/?utm_source=ig_web_copy_link&igsh=MzRlODBiNWFlZA==\n\nhttps://www.instagram.com/p/DPO3m56iPc6/?utm_source=ig_web_copy_link&igsh=MzRlODBiNWFlZA=="},{"label":"What font preferences do you have or would you like to see in your designs? If you are open to our recommendations, please feel free to mention it below:","value":"open to recommendations"},{"label":"What would success look like working together?","value":"My instagram following and flow would expand over the next 6 months to 100k followers who are interested in this work."},{"label":"Anything else we should know?","value":"I will answer and send the other links later just wanted to get this done!"}]'::jsonb, 'notion-legacy', '2025-10-23T05:22:00.000Z')
