insert into public.legacy_onboarding (id, slug, first_name, last_name, email, phone, submitted_on, fields, source, created_at)
values ('2a1bcb82c4bf818ea55ce3846b807258', 'morganburton', 'Morgan', 'Burton', 'morgancarringtonburton@gmail.com', '5127792554', 'November 4, 2025 4:38 PM', '[{"label":"Who will need to be included in communication about the work we’re doing?","value":"Morgan Andrea - morgan@wildpowerfulstudio.com"},{"label":"Accounting Contact","value":"n/a"},{"label":"Who is your IDEAL target customer?","value":"My ideal client is an evolved entrepreneur, creative, or service provider who has done the inner work — personally, spiritually, and emotionally — but feels like their presence hasn’t caught up with who they’ve become.\nThey’re not beginners. They’ve built something before, seen success, and know they’re meant for more — but right now, their expression, structure, or systems feel outdated or disconnected from their current truth.\nThey are:\n• Self-aware and growth-minded — they crave depth, honesty, and alignment over quick fixes.\n• Multi-dimensional — they have layers: creativity, spirituality, strategy, and leadership.\n• Ready for recalibration — they want to rebuild their presence, offers, and rhythm in a way that feels sustainable and real.\n• Open to both structure and surrender — they value strategic direction but also trust intuitive guidance and embodiment work.\n• Seeking ease and authenticity — they’re tired of performing and ready to be seen for who they actually are.\nThey’re not looking for someone to tell them who to be — they’re looking for a mirror, a guide, and a safe space to come home to themselves and create from that place again."},{"label":"Do you have any brand identity or guidelines that you have available for reference? If so, please share the link below:","value":"https://trello.com/1/cards/67efd408e2dd053e66b7b7de/attachments/67f5270cb62d62a1c716d0f7/download/photo.jpeg ; https://trello.com/1/cards/67efd405c3ea21d7327e3832/attachments/67efd417c8ef6e5c1f0be69e/download/5.png"},{"label":"What are the PAIN points of the customers you help?","value":"Most of the people I guide are in a season of transition — they’ve grown, evolved, and healed, but their presence hasn’t caught up. They feel a disconnect between who they are now and how they’re being seen.\nThey often feel:\n• Misaligned and unclear — their message, offers, or online presence no longer reflect what they truly do or stand for.\n• Stuck in reinvention mode — knowing something needs to shift but not sure where to start or how to bring all their ideas together.\n• Overwhelmed by visibility — they want to show up, but overthinking and self-comparison keep them from being consistent.\n• Disconnected from their own voice — they’ve taken in so much advice that their natural tone and rhythm have gotten lost.\n• Burnt out from doing it all — their systems, routines, and content flow don’t support who they’re becoming, leaving them tired and uninspired.\n• Ready for deeper alignment — they don’t just want a new strategy; they want to feel grounded in their purpose and clear in their next steps."},{"label":"What are the DESIRED OUTCOMES of the customers you help?","value":"The people I guide come to me when they’ve outgrown their old way of showing up. They’ve evolved personally, but their presence hasn’t caught up — and they’re ready to close that gap.\nThrough this work, they walk away with:\n• A renewed sense of clarity and confidence — knowing exactly who they are in this season and how to express that in their life, content, and conversations.\n• A presence that feels like them again — grounded, magnetic, and authentic, without having to force or perform.\n• Offers and systems that match their true capacity — built around what actually lights them up, not what drains them.\n• A consistent rhythm of visibility — where showing up online feels easy, aligned, and sustainable instead of overwhelming.\n• A deeper connection to their voice and body — through somatic work and breath practices that regulate their nervous system and bring their message to life.\n• Realigned momentum — where their inner world, presence, and business finally move in the same direction."},{"label":"What is your PROCESS for helping clients get from where they are to where they want to go?","value":"My work is about guiding you through a full transformation — not just in your business, but in how you show up. I call it the Aligned Presence Method, and it’s designed to take you from who you were to who you actually are now.\n1. Reveal — We start by peeling back the layers. Through deep reflection and conversation, we uncover who you are in this season — what you value, what’s shifted, and what you actually want your presence and work to feel like.\n2. Refine — Then we sharpen the message. We clarify your voice, energy, and rhythm so your content, visuals, and offers communicate your truth with ease and confidence.\n3. Rebuild — This is where we bring structure to your vision. Together, we design the systems, offers, and visibility flow that support your growth — in a way that feels natural, not forced.\n4. Root — Finally, we anchor it all. Through breathwork, embodiment, and consistent presence practices, you integrate what you’ve created so it becomes your new normal — not just an idea you’re chasing.\nIt’s equal parts strategy, energy, and embodiment — a process that reconnects you to your voice, rebuilds your presence from a place of truth, and roots you in the version of yourself you’ve been becoming all along."},{"label":"Please provide links to some examples of social media clips that you like from a design perspective:","value":"https://www.instagram.com/p/DQmlA9IjwaH/\nhttps://www.instagram.com/p/DP_xoYGCWSF/\nhttps://www.instagram.com/reel/DQWsqz1jX9Q/?igsh=anpoYmhtMzh4c2pp"},{"label":"Please provide links to video thumbnails/cover images that you like from a design perspective:","value":"n/a"},{"label":"What font preferences do you have or would you like to see in your designs? If you are open to our recommendations, please feel free to mention it below:","value":"open to recommendations - I like a simple look, please see current IG graphics"},{"label":"What color preferences do you have or would you like to see in your designs?","value":"https://drive.google.com/drive/folders/1_MhXWHuAsAHiTJX3HFL1nyyDzs6LT5RX?usp=share_link"},{"label":"Google Drive Link to pictures of yourself","value":"https://drewelaine.pixieset.com/morgan/"},{"label":"Google Doc Link to links to podcast, speeches or any other video content you want us to create content from","value":"https://drive.google.com/drive/folders/1pDF3sSQB33mP5Os-pV7E9jGkVyyPcwcu"},{"label":"What would success look like working together?","value":"I want to fully trust the team and know that I can provide the video and step back!"},{"label":"Anything else we should know?","value":"n/a"}]'::jsonb, 'notion-legacy', '2025-11-04T16:38:00.000Z')
