values ('2c0bcb82c4bf81c98d58ec281a1bd6d0', 'annielalla', 'Annie', 'Lalla', 'lallabird@gmail.com', '9173189929', 'December 5, 2025 5:09 PM', '[{"label":"Who will need to be included in communication about the work we’re doing?","value":"Eben Pagan: e@ebenpagan.com\nJoe Muscatello: joe@ebenpagan.com (Designer/ Video)\nMegan Lara: megan@ebenpagan.com (COO/ Invoices)\nSylvia Ferrero: sylvia@heartcoach.com"},{"label":"Accounting Contact","value":"Sylvia my Project Manager: sylvia@heartcoach.com"},{"label":"Who is your IDEAL target customer?","value":"Singles ready to find their soulmate. Couples who want to make their love last forever"},{"label":"Old website","value":"www.lovedojo.com"},{"label":"Do you have any brand identity or guidelines that you have available for reference? If so, please share the link below:","value":"https://drive.google.com/file/d/13tqTjOmJ_W6HMNfHkDBTqiSoXkQdNiDF/view?usp=drive_link"},{"label":"What are the PAIN points of the customers you help?","value":"Fighting/ Recurrent Conflict/ Fear of breaking up/ Coping with shame, jealousy/ Avoiding Divorce/ Reconciling differing values"},{"label":"What are the DESIRED OUTCOMES of the customers you help?","value":"End Conflict & Fighting/ True Love, Life long romance that works/ Healthy relationship/ Marriage/ Passionate sex life/ Being a Power Couple/ Building a family/ Evolving together"},{"label":"What is your PROCESS for helping clients get from where they are to where they want to go?","value":"Transforming conflict into collaboration, learning partners values, building a solid relationship toolkit, building cutting-edge emotional skills, teaching self-regulation techniques, showing them how to manufacture faith from despair & darkness"},{"label":"Please provide links to some examples of social media clips that you like from a design perspective:","value":"https://www.instagram.com/thelaylamartin\nhttps://www.instagram.com/emilystellafletcher\nhttps://www.instagram.com/jessicazweig/"},{"label":"Please provide links to video thumbnails/cover images that you like from a design perspective:","value":"I like clear pics with purple/ pink colored lights in background"},{"label":"What font preferences do you have or would you like to see in your designs? If you are open to our recommendations, please feel free to mention it below:","value":"sans serif, modern, Avenir-style"},{"label":"What color preferences do you have or would you like to see in your designs?","value":"https://lovedojo.com/"},{"label":"Google Doc Link to links to podcast, speeches or any other video content you want us to create content from","value":"https://docs.google.com/document/d/1iPetuqplY_0iU5XdEW4ON3X_M60f8drAd7ILmOYhxAE/edit?usp=sharing"},{"label":"What would success look like working together?","value":"increase in followers with short form, linked to long form content for conversions"},{"label":"Anything else we should know?","value":"https://docs.google.com/document/d/1iPetuqplY_0iU5XdEW4ON3X_M60f8drAd7ILmOYhxAE/edit?usp=sharing"}]'::jsonb, 'notion-legacy', '2025-12-05T17:09:00.000Z')
