insert into public.legacy_onboarding (id, slug, first_name, last_name, email, phone, submitted_on, fields, source, created_at)
values ('320bcb82c4bf817f9abec965eaf66179', 'jesseisrael', 'Jesse', 'Israel', 'j@jesseisrael.com', '310 922 2807', 'March 11, 2026 4:47 PM', '[{"label":"Who will need to be included in communication about the work we’re doing?","value":"My EA, Abby Hildebrand. Not quite sure yet where she will need to be included: abby@jesseisrael.com"},{"label":"Accounting Contact","value":"N/A"},{"label":"Who is your IDEAL target customer?","value":"I think the closest example to how I''d like to position myself is Jay Shetty, but done my own way. Unlike other creators who focus on a specific niche, I would like to stand for and offer more of an umbrella approach to the intersection of consciousness, personal growth, human connection and culture. I believe my target customer is similar to Jay Shetty: people who are interested in increasing their consciousness, working on themselves, growing, healing, transforming, finding support and knowledge - but want it presented in a way that feels relatable, cool, humorous and in touch with culture."},{"label":"Do you have any brand identity or guidelines that you have available for reference? If so, please share the link below:","value":"Not at the moment"},{"label":"What are the PAIN points of the customers you help?","value":"People that yearn to live as more of their true selves. That want to become more of the person they are here to be. People that feel disconnected from themselves, from their inner power, from their gifts and their agency. People who feel overwhelmed by the intensity of the world today. People who know that there are other ways to live - with more freedom, with more connection to self and others, with more purpose. Pain points include feeling stuck, feeling small, feeling afraid to live life more fully, feeling overwhelmed, anxious, in their heads."},{"label":"What are the DESIRED OUTCOMES of the customers you help?","value":"People living as the person they are on this earth to be. People that feel alive. Clear. In their power, in their purpose, on mission. Expressive of their greatest gifts. More themselves. Easier to connect with others."},{"label":"What is your PROCESS for helping clients get from where they are to where they want to go?","value":"It varies -- in my keynotes, it''s about teaching about my Amplified Quiet Framework to help audiences quiet noise so they can realize more of their potential and unlock what''s possible in work and life - which includes themes like: making space (still space, solo space, analog space), changing our relationships with our phones and devices, human connection, being of service, assigning meaning to what you do, sharing your gifts, embracing discomfort, acting with courage. If I had to simplify it, it would probably be these buckets: (1) connection with self (2) connection with others (3) connection with the world. In my coaching business, it''s 1:1 work that relies on meditation training, emotional release work, inner child work, mindset work. I''m not totally clear on how this all translates to socials."},{"label":"Please provide links to some examples of social media clips that you like from a design perspective:","value":"https://www.instagram.com/reels/DRxYDohgYiR/\nhttps://www.instagram.com/reels/DTx_S1UABix/\nhttps://www.instagram.com/reels/DJXFz7_P212/\nhttps://www.instagram.com/reels/DVJb2DACXoO/\nhttps://www.instagram.com/reels/DU6ElFHFlrY/"},{"label":"Please provide links to video thumbnails/cover images that you like from a design perspective:","value":"https://www.instagram.com/tomnoske/\nhttps://www.instagram.com/attentioncompound/\nhttps://www.instagram.com/colinandsamir/\nhttps://www.instagram.com/manojdias_/\nhttps://www.instagram.com/jayshetty"},{"label":"What font preferences do you have or would you like to see in your designs? If you are open to our recommendations, please feel free to mention it below:","value":"OPEN TO RECOMMENDATIONS\nhttps://www.instagram.com/reels/DUzPuILieLs/\nhttps://www.instagram.com/reels/DU6ElFHFlrY/\nhttps://www.instagram.com/reels/DGWm59DydBi/\nhttps://www.instagram.com/reels/DKmp5taN0LB/\nhttps://www.instagram.com/reels/DMqPoFeSYyr/"},{"label":"What color preferences do you have or would you like to see in your designs?","value":"White and yellow"},{"label":"Google Drive Link to pictures of yourself","value":"https://drive.google.com/drive/folders/10aEdpmDPz_mQvLfPiMzNnF1ZVJ2g-7T5?usp=sharing"},{"label":"Google Doc Link to links to podcast, speeches or any other video content you want us to create content from","value":"https://drive.google.com/drive/folders/1Wck5hGJf8PwKJcB6ukIpNUBOTFpgtqSO?usp=sharing"},{"label":"What would success look like working together?","value":"Phase 1\n- clear strategy for testing different types of content that feel good and authentic to make\n- process and systems dialed\n- creating and posting regularly (3x weekly)\n- seeing real engagement and genuine audience growth\n- content is actually helping my audience and creating value for them\n\nPhase 2\n- honed in content approach / we know what''s working and are doubling down\n- incorporation of podcast or online show / series\n- 100k+ followers\n\nPhase 3\n- focus on refining and mastering effective content\n- 500k+ followers"},{"label":"Anything else we should know?","value":"I''m looking for guidance on how to position myself on socials in a way that isn''t just about meditation (focusing only on meditation and mindfulness doesn''t excite me). Eager to explore how to best do this.\n\nPlease check out my website to better understand the work I do as a keynote speaker: www.jesseisrael.com\n\nTo understand my previous work with the big quiet, please watch this short 3 min film: youtube.com/watch?v=Gn2IgjqQbW0&themeRefresh=1\n\nAnd to better understand how I''ve worked with brands in the past: https: //www.jesseisrael.com/collabs"}]'::jsonb, 'notion-legacy', '2026-03-11T16:47:00.000Z')
on conflict (id) do update set slug=excluded.slug, first_name=excluded.first_name, last_name=excluded.last_name, email=excluded.email, phone=excluded.phone, submitted_on=excluded.submitted_on, fields=excluded.fields, source=excluded.source, created_at=excluded.created_at;

insert into public.legacy_onboarding (id, slug, first_name, last_name, email, phone, submitted_on, fields, source, created_at)
values ('2e3bcb82c4bf81b385d5c6133e6b4872', 'morganburch', 'Morgan', 'Burch', 'morgan@morganburch.com', '917-828-6144', 'January 8, 2026 10:20 PM', '[{"label":"Who will need to be included in communication about the work we''re doing?","value":"addie@goodmorgantherapy.com"},{"label":"Accounting Contact","value":"sharon@sharonburch.com; addie@goodmorgantherapy.com"},{"label":"Who is your IDEAL target customer?","value":"Couples who are fed up but don''t want to give up. Ages 35-75 usually."},{"label":"Do you have any brand identity or guidelines that you have available for reference? If so, please share the link below:","value":"https://www.canva.com/design/DAG9giqc9ZA/2FlzFAdDcR_dDCsh_rLJ6Q/view?utm_content=DAG9giqc9ZA&utm_campaign=designshare&utm_medium=link2&utm_source=uniquelinks&utlId=h78a329f322"},{"label":"What are the PAIN points of the customers you help?","value":"They aer on the brink of divorce. they feel misunderstood, unseen, sick of walking on eggshells, sick of broken promises, sick of broken trust, recovering from betrayals of various kinds, most of all RESENTMENT so much resentment. They want to break the cycles and are afraid they can''t do that without breaking the relationship. Sick of living in the doghouse. sick of feeling let down. sick of feeling alone. sick of feeling like there''s no room for them in the relationship."},{"label":"What are the DESIRED OUTCOMES of the customers you help?","value":"They want to find their way back to each other, even after life, logistics, and resentment buried their spark. They want to make their next chapter the best one."},{"label":"What is your PROCESS for helping clients get from where they are to where they want to go?","value":"The SEEN Method. For the sake of time, I won''t explain it here but you''ll see many videos. It''s a method that cuts through to the quiet real issue under the loud symptoms of the real issue."},{"label":"Please provide links to some examples of social media clips that you like from a design perspective:","value":"https://www.instagram.com/reel/DSqxrR3kXIi/?utm_source=ig_web_copy_link&igsh=MzRlODBiNWFlZA==\n\nI love the idea of getting a bit of a variety! Dan and I doing reels, me recording in my office, podcast clips, speaking clips...\n\nFor the clips in my office I like editing that embraces me running around dancing - zooming in and out. There''s an art to it that doesn''t look AI at all which is awesome.\n\nThis is my favorite example of how I want to write, perform, and edit: https://www.instagram.com/reel/DCAI_QqtCgi/?utm_source=ig_web_copy_link&igsh=MzRlODBiNWFlZA==\n\nhttps://www.instagram.com/reel/DRhbe-vCgC8/?utm_source=ig_web_copy_link&igsh=MzRlODBiNWFlZA==\n\nhttps://www.instagram.com/reel/DRptKGCEpMS/?utm_source=ig_web_copy_link&igsh=MzRlODBiNWFlZA==\n\nhttps://www.instagram.com/reel/DQpIryxjSZO/?utm_source=ig_web_copy_link&igsh=MzRlODBiNWFlZA=="},{"label":"Please provide links to video thumbnails/cover images that you like from a design perspective:","value":"Favorite thumbnail of all: https://youtu.be/E0NnkfNd5o0?si=rjBFRXnKGJVyLGmX\n\nOthers that are cool (there''s a variety because I''m not sure where to land with ours):\nhttps://youtu.be/qEA2QjU7l2k?si=tSopy1Il2j-Y6UIN\n\nhttps://youtu.be/JnAl1PfAIvg?si=vLA-YM6anv2s55-W\n\nhttps://youtu.be/V_Z8XoPVDBg?si=L80Pv5hY3gxboWDY\n\nhttps://youtu.be/B5q9hCbga44?si=K_CbDzFmaf9_qmSM\n\nhttps://youtu.be/WYhQnzIYxQs?si=CQ1K582aDtyx7Ghl\n\nhttps://youtu.be/Ch4Sl0POBhU?si=rEv6byzdDbt7aysy"},{"label":"What font preferences do you have or would you like to see in your designs? If you are open to our recommendations, please feel free to mention it below:","value":"captions/subtitles: Fraunces Bold - typically in white and soft sky blue - #6ea7dd\n\nbody text: Mulish 300 - typically in black #3e3e3e\nheadlines: Noto Serif JP 700 - typically in Navy #003166\nTaglines: Dancing Script - typically in black #3e3e3e"},{"label":"What color preferences do you have or would you like to see in your designs?","value":"LOVE bright red so much.\n\nAll Brand Colors:\n#ff4937 - bright soft red\n#f40134 - bright red\n#ffbd59 - Yellow\n#ff3d00 - Orange/Red\n#ff4a00 - Vivid Orange\n#f15827 - mature orange\n#cfe5ff - Soft Light Blue\n#6ea7dd - Soft Sky Blue\n#9cdcf9 - Bright Blue (Pastel Azure)\n#022963 - Dark Navy\n#253d84 - True Navy\n#070504 - Black\n#fbe4de - Light Pink\n#ee6774 - Salmon Pink\n#53b462 - Bright Soft Green\n#88bb90 - Royal Green"},{"label":"Google Drive Link to pictures of yourself","value":"https://drive.google.com/drive/folders/1hpY71_f9wuHDd6gM6gfVctLT4497uQNy?usp=drive_link"},{"label":"What would success look like working together?","value":"leaving blank for the sake of time!"},{"label":"Anything else we should know?","value":"The tech side of getting you logged in might require a scheduled time to figure out together. I hate to be so daft and cause extra work for you but I''m a bit stumped and don''t want to delay submitting this any longer."}]'::jsonb, 'notion-legacy', '2026-01-08T22:20:00.000Z')
